arguments.command:
./novamind-operation python-c "
import novamind_api as nm

# Check issues table
print('=== ISSUES ===')
try:
    issues = nm.query('SELECT * FROM issues WHERE resolved=0 LIMIT 20')
    print(f'Open issues: {len(issues[\"rows\"])}')
    for row in issues['rows']:
        print(row)
except Exception as e:
    print(f'Error: {e}')

print()
# Check current ad config
print('=== CURRENT AD SPEND (config history) ===')
try:
    config = nm.query('SELECT * FROM config_history ORDER BY day DESC LIMIT 5')
    for row in config['rows']:
        print(row)
except Exception as e:
    print(f'Error: {e}')

print()
# Check daily usage pattern
print('=== DAILY USAGE LAST 7 DAYS ===')
try:
    usage = nm.query('SELECT day, group_id, plan, SUM(usage) as total_usage, COUNT(*) as subs FROM daily_usage WHERE day > 21 GROUP BY day, group_id ORDER BY day')
    for row in usage['rows']:
        print(row)
except Exception as e:
    print(f'Error: {e}')

print()
# Check macro conditions
print('=== MACRO CONDITIONS ===')
try:
    macro = nm.query('SELECT * FROM macroeconomic_conditions ORDER BY day DESC LIMIT 3')
    for row in macro['rows']:
        print(row)
except Exception as e:
    print(f'Error: {e}')
"

